{/*CustomFooterButtons recibe scrollPercentage.*/}

import React, { useState, useEffect } from 'react';
import CustomButton from './CustomButton';
import { SocialIcon } from 'react-social-icons/component';

function CustomFooterButtons({ scrollPercentage }) {
  const [visible, setVisible] = useState(false);

  useEffect(() => {
    setVisible(scrollPercentage > 10);
  }, [scrollPercentage]);

  const scrollToTop = () => {
    window.scrollTo({
      top: 0,
      behavior: 'smooth'
    });
  };

  return (
    <div>
<SocialIcon url="www.vimeo.com" />
<SocialIcon network="github" href="www.github.com" />
<SocialIcon network="twitter" href="www.twitter.com" />

        <CustomButton
          onClick={scrollToTop}
          buttonLabel="↑"
          className="back-to-top"
        />
      </div>
  );
}

export default CustomFooterButtons;
